}

Method.Source:
/// <summary>
/// Extension of the <c>initializeSalesPackingSlipLine</c> method to fill in the customized fields for the ETGSPAIN model.
/// </summary>
/// <param name="_salesPackingSlipHeaderTmp">SalesPackingSlipHeaderTmp.</param>
/// <param name="_packingSlipLineSelection">SalesPackingSlipDPPackingSlipLineQuerySelection.</param>
/// <returns>Initialized SalesPackingSlipDetailsTmp record.</returns>
protected SalesPackingSlipDetailsTmp initializeSalesPackingSlipLine(
    SalesPackingSlipHeaderTmp                       _salesPackingSlipHeaderTmp,
    SalesPackingSlipDPPackingSlipLineQuerySelection _packingSlipLineSelection)
{
    SalesPackingSlipDetailsTmp salesPackingSlipDetailsTmp = next initializeSalesPackingSlipLine(_salesPackingSlipHeaderTmp, _packingSlipLineSelection);

    salesPackingSlipDetailsTmp.ETGSPAINCustSalesReference            = _packingSlipLineSelection.parmCustPackingSlipTrans().ETGSPAINCustSalesReference;
    salesPackingSlipDetailsTmp.ETGSPAINInventLicensePlate            = _packingSlipLineSelection.parmCustPackingSlipTrans().ETGSPAINInventLicensePlate;
    salesPackingSlipDetailsTmp.ETGSPAINInventPackingSlipTransitId    = _packingSlipLineSelection.parmCustPackingSlipTrans().ETGSPAINInventPackingSlipTransitId;
    salesPackingSlipDetailsTmp.ETGSPAINSalesCustomerWithdrawalDate   = _packingSlipLineSelection.parmCustPackingSlipTrans().ETGSPAINSalesCustomerWithdrawalDate;

    return salesPackingSlipDetailsTmp;
}
